  // ── MC Question Frames ──
  tk_mc_choose:          {en:"Choose the correct answer",nl:"Kies het juiste antwoord"},
  tk_mc_which_sound:     {en:"Which sound does this represent?",nl:"Welk geluid hoort hierbij?"},
