export const localize=(targetLang,baseLang,key)=>{
  const dict=I18N[targetLang]?.[baseLang];
  if(dict&&dict[key])return dict[key];
  const en=I18N[targetLang]?.en;
  if(en&&en[key])return en[key];
  return key.replace(/_/g," ");
};

