// Build reverse lookup: word → lexeme id
export const LEXEME_BY_WORD={};
Object.entries(LEXEMES).forEach(([id,lx])=>{
  LEXEME_BY_WORD[`${lx.lang}:${lx.lemma}`]=id;
  (lx.forms||[]).forEach(f=>{LEXEME_BY_WORD[`${lx.lang}:${f}`]=id;});
});
export const getLexeme=(lang,word)=>LEXEME_BY_WORD[`${lang}:${word?.toLowerCase?.()}`]||LEXEME_BY_WORD[`${lang}:${word}`]||null;

