// Backward-compatible API — resolves per language
export const ARTICLE_COLORS = (() => {
  // Merge all language colors into flat map for backward compat
  const flat = { none: ARTICLE_NONE };
  Object.values(ARTICLE_SYSTEMS).forEach(sys => {
    Object.entries(sys.colors).forEach(([art, col]) => { flat[art] = col; });
  });
  return flat;
})();

export function getArticle(word, lang) {
  const sys = ARTICLE_SYSTEMS[lang || "nl"];
  if (sys) return sys.detect(word);
  // Fallback: try all systems
  for (const s of Object.values(ARTICLE_SYSTEMS)) {
    const r = s.detect(word);
    if (r !== "none") return r;
  }
  return "none";
}

